class Solution {
public:
    long long findMaximumNumber(long long k, int x) {
        long long l = 1, r = k * 100;
        while (l < r) {
            long long mid = l + (r - l) / 2;
            long long sum = 0;
            for (long long i = 1; i <= mid; i++) {
                long long j = i, cnt = 0;
                while (j > 0) {
                    if (j & 1) cnt++;
                    j /= x;
                }
                sum += cnt;
            }
            if (sum <= k) l = mid + 1;
            else r = mid;
        }
        return l - 1;
    }
};
